const t=JSON.parse('{"key":"v-16794481","path":"/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/14-%E8%9C%A1%E7%83%9B%E5%9B%BE%E4%B8%8E%E6%9C%9F%E6%9D%83%E4%BA%A4%E6%98%93.html","title":"蜡烛图与期权交易","lang":"zh-CN","frontmatter":{"date":"2024-01-17T00:00:00.000Z","category":["证券交易"],"tag":["期权交易"],"order":14,"description":"蜡烛图与期权交易 有时候，期权交易同它所对应的一般市场比起来，有其独特优势。具体来说，期权交易提供了下述几方面的优势： 1.忍峙能力--买入期权的风险，仅限于最初支付的期权费。因此，当我们企图押一押市场顶部或底部时，期权是合适的工具。这类头寸风险极大，但是如果我们审慎地以期权作为交易媒介，则有助于减少这类交易的先天性风险。 2.在横向延伸市场状况下的获利能--当相应的期货市场处于水平交易区间中时，通过期权的运用，我们仍可以从这种行情中获利（方法是卖出跨式期权或者其它的期权组合）。 3.交易策略的灵活性--借助期权交易，我们能够调整风险/报偿的参数，以适应自己对价格、市场波动性、交易时机等市场要素的预测。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/14-%E8%9C%A1%E7%83%9B%E5%9B%BE%E4%B8%8E%E6%9C%9F%E6%9D%83%E4%BA%A4%E6%98%93.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"蜡烛图与期权交易"}],["meta",{"property":"og:description","content":"蜡烛图与期权交易 有时候，期权交易同它所对应的一般市场比起来，有其独特优势。具体来说，期权交易提供了下述几方面的优势： 1.忍峙能力--买入期权的风险，仅限于最初支付的期权费。因此，当我们企图押一押市场顶部或底部时，期权是合适的工具。这类头寸风险极大，但是如果我们审慎地以期权作为交易媒介，则有助于减少这类交易的先天性风险。 2.在横向延伸市场状况下的获利能--当相应的期货市场处于水平交易区间中时，通过期权的运用，我们仍可以从这种行情中获利（方法是卖出跨式期权或者其它的期权组合）。 3.交易策略的灵活性--借助期权交易，我们能够调整风险/报偿的参数，以适应自己对价格、市场波动性、交易时机等市场要素的预测。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-01-28T15:56:15.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"期权交易"}],["meta",{"property":"article:published_time","content":"2024-01-17T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-01-28T15:56:15.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"蜡烛图与期权交易\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-01-17T00:00:00.000Z\\",\\"dateModified\\":\\"2024-01-28T15:56:15.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"期权的基础知识","slug":"期权的基础知识","link":"#期权的基础知识","children":[]},{"level":2,"title":"期权交易与蜡烛图","slug":"期权交易与蜡烛图","link":"#期权交易与蜡烛图","children":[]}],"git":{"createdTime":1706369720000,"updatedTime":1706457375000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":2}]},"readingTime":{"minutes":14.25,"words":4276},"filePathRelative":"证券交易/日本蜡烛图技术/14-蜡烛图与期权交易.md","localizedDate":"2024年1月17日","excerpt":"<h1> 蜡烛图与期权交易</h1>\\n<p>有时候，期权交易同它所对应的一般市场比起来，有其独特优势。具体来说，期权交易提供了下述几方面的优势：</p>\\n<p>1.忍峙能力--买入期权的风险，仅限于最初支付的期权费。因此，当我们企图押一押市场顶部或底部时，期权是合适的工具。这类头寸风险极大，但是如果我们审慎地以期权作为交易媒介，则有助于减少这类交易的先天性风险。</p>\\n<p>2.在横向延伸市场状况下的获利能--当相应的期货市场处于水平交易区间中时，通过期权的运用，我们仍可以从这种行情中获利（方法是卖出跨式期权或者其它的期权组合）。</p>\\n<p>3.交易策略的灵活性--借助期权交易，我们能够调整风险/报偿的参数，以适应自己对价格、市场波动性、交易时机等市场要素的预测。</p>","autoDesc":true}');export{t as data};
